var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>식별 불가의 제 5종 침식체, 침묵!</color>","JPN":"<color=#ffd34c>識別不可の第5種侵食体、沈黙！</color>","ENG":"<color=#ffd34c>Unidentified Category 5 C.O., silenced!</color>","TWN":"<color=#ffd34c>無法辨別的5類侵蝕體，沉默！</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>아줌마, 진짜 쓰러뜨렸어!</color>","JPN":"<color=#ffd34c>おばさん、マジで倒したんだ！</color>","ENG":"<color=#ffd34c>Maria, you actually defeated it!</color>","TWN":"<color=#ffd34c>大嬸打贏咧！</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>가르강튀아의 에너지 소모량도 안정적이야.</color>","JPN":"<color=#ffd34c>ガルガンティアのエネルギー消費量も安定してる。</color>","ENG":"<color=#ffd34c>Also, even Garguantia’s energy consumption is stable.</color>","TWN":"<color=#ffd34c>加爾剛迪亞的動能耗損量也還在安全範圍內。</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>연속 전투는 무리겠지만 이 정도라면 실전배치도 문제 없어.</color>","JPN":"<color=#ffd34c>続けての戦闘は無理だけど、このくらいなら実戦への配置も問題なさそうだね。</color>","ENG":"<color=#ffd34c>We won’t be able to fire it non-stop, but based on what I’m seeing, we shouldn’t have any issues deploying it for actual battles.</color>","TWN":"<color=#ffd34c>雖然無法連續戰鬥，但還是可以用來應付這種程度的作戰的。</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"후후, 고생한 만큼의 가치는 있어서 다행이군.","JPN":"ふふ、苦労した甲斐があってよかったな。","ENG":"Haha. I’m glad to hear that the result was worth the effort.","TWN":"呵呵，幸好辛苦是有價值的！"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"그보다 엔터프라이즈 쿼드는 준비됐나?","JPN":"それより、エンタープライズクワッドの準備はいいか？","ENG":"Anyway, is the Enterprise Quad ready?","TWN":"不過企業4號準備得如何？"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>1차 시스템 조정은 끝났어.</color>","JPN":"<color=#ffd34c>一次システム調整はできたわ。</color>","ENG":"<color=#ffd34c>The 1st system adjustment is completed.</color>","TWN":"<color=#ffd34c>第1波系統調整已完成。</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>제성능을 완전히 끌어내려면 시간이 필요하겠지만, 지금도 작전 행동은 문제 없을 거야.</color>","JPN":"<color=#ffd34c>元の性能を完璧に引き出すためには時間が必要だけど、今も作戦行動には問題ないはずよ。</color>","ENG":"<color=#ffd34c>We’ll need more time to utilize its full capacity, but she should be ready for operational deployment now.</color>","TWN":"<color=#ffd34c>雖然還需要些時間才能將性能完全發揮出來，但目前是可以運用在作戰上的。</color>"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"좋아, 그러면 즉시 출항한다.","JPN":"よし、それではすぐに出航する。","ENG":"Good, then let’s set out immediately.","TWN":"很好，那就立刻啟航吧。"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"기지 내에 있는 모든 대원들에게 즉시 탑승 명령을 전달하도록!","JPN":"基地内の全隊員に即搭乗命令を伝えろ！","ENG":"Order all personnel within base to board the ship immediately!","TWN":"立刻下令要基地內的所有隊員搭上艦船！"},"stage":{"bg":"MS_905","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"후우…… 지치는군.","JPN":"ふう……疲れるな。","ENG":"Phew... That was exhausting.","TWN":"呼……好累。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"괜찮으십니까, 사령관님? 부축해 드리겠습니다.","JPN":"司令官、大丈夫ですか？　お助けいたします。","ENG":"Are you okay, Commander? Let me support you.","TWN":"司令官，您還好嗎？我扶您。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"음. 고맙군, 카일.","JPN":"うむ。ありがとう、カイル。","ENG":"Mmph. Thank you, Kyle.","TWN":"嗯，謝謝你，凱爾。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"역시 세월에는 당해낼 수 없는 모양이야.","JPN":"やはり寄る年波には勝てないな。","ENG":"I guess nothing can beat time.","TWN":"我果然是敵不過歲月。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아닙니다. 마치 대정화 전쟁 당시의 활약상을 제 눈으로 직접 보는 것 같았습니다.","JPN":"滅相もない。まるで大浄化戦争当時のご活躍をこの目で確かめるかのようでした。","ENG":"You’re being modest. It was as if I were seeing your feats in person during the Grand Purification War.","TWN":"沒的事，我彷佛像親見到大淨化戰爭當時的司令官一般。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 카일 녀석 잔뜩 신났군.","JPN":"はは、カイルのやつ、浮かれてるな。","ENG":"Haha, Kyle seems very excited.","TWN":"哈哈，凱爾這這傢伙很興奮呢。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"다른 군인 아저씨들도 비슷하던데, 뭐. 전장의 여신이 나타났다면서 온통 호들갑이야.","JPN":"まあ、他の軍人も似たりよったりよ。戦場の女神が現れたって大騒ぎしてる。","ENG":"The other troopers are like him as well. They’re saying all these things about the warrior goddess appearing before us.","TWN":"其他軍人大叔不也是嗎，在那邊大吼大叫說什麼戰爭女神來啦～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};